// Dynamic metadata function
export async function generateMetadata({ params }) {
  const { marketInsightId } = params;
  const marketInsightsData = posts.find(
    (marketInsight) => marketInsight.id === marketInsightId
  );

  let title = "";
  let description = "";
  if (marketInsightsData) {
    title = marketInsightsData.metaTitle || title;
    description = marketInsightsData.metaDescription || description;
  }

  return {
    title,
    description,
  };
}

function Page({ params }) {
  const marketInsightsData = posts.find(
    (marketInsight) => marketInsight.id === params.marketInsightId
  );
  const jsonLd = marketInsightsData?.schemas;

  return (
    <div>
      {jsonLd ? (
        <Script
          id={`market-insight-jsonld-${marketInsightsData.id}`}
          type="application/ld+json"
          strategy="afterInteractive"
          dangerouslySetInnerHTML={{ __html: JSON.stringify(jsonLd) }}
        />
      ) : null}
      <MarketInsightsDetailPage params={params} />
    </div>
  );
}

export default Page;
